changeSet.sql:
-- Create Table: roles CREATE TABLE roles ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name VARCHAR(100) NOT NULL UNIQUE, description VARCHAR(255) );
-- Create Table: users CREATE TABLE users ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), full_name VARCHAR(255) NOT NULL, email VARCHAR(255) NOT NULL UNIQUE, password_hash VARCHAR(60) NOT NULL, role_id UUID NOT NULL, status VARCHAR(50) NOT NULL DEFAULT 'ACTIVE', created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, CONSTRAINT fk_users_role FOREIGN KEY (role_id) REFERENCES roles(id) ON DELETE RESTRICT );
-- Create Table: product_categories CREATE TABLE product_categories ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name VARCHAR(255) NOT NULL UNIQUE, description VARCHAR(255) );
-- Create Table: warehouses CREATE TABLE warehouses ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name VARCHAR(255) NOT NULL, location VARCHAR(255), manager_id UUID, CONSTRAINT fk_warehouses_manager FOREIGN KEY (manager_id) REFERENCES users(id) ON DELETE SET NULL );
-- Create Table: products CREATE TABLE products ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), sku VARCHAR(50) NOT NULL UNIQUE, name VARCHAR(255) NOT NULL, description VARCHAR(255), category_id UUID, unit_price DECIMAL(12, 2) NOT NULL DEFAULT 0.00, stock_quantity INTEGER NOT NULL DEFAULT 0, reorder_level INTEGER NOT NULL DEFAULT 10, warehouse_id UUID, is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, CONSTRAINT fk_products_category FOREIGN KEY (category_id) REFERENCES product_categories(id) ON DELETE SET NULL, CONSTRAINT fk_products_warehouse FOREIGN KEY (warehouse_id) REFERENCES warehouses(id) ON DELETE SET NULL, CONSTRAINT check_positive_stock CHECK (stock_quantity >= 0), CONSTRAINT check_positive_reorder CHECK (reorder_level >= 0) );
-- Create Table: inventory_transactions CREATE TABLE inventory_transactions ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), product_id UUID NOT NULL, warehouse_id UUID NOT NULL, type VARCHAR(50) NOT NULL, quantity INTEGER NOT NULL, reference_type VARCHAR(100), reference_id UUID, performed_by UUID, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, CONSTRAINT fk_transactions_product FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE RESTRICT, CONSTRAINT fk_transactions_warehouse FOREIGN KEY (warehouse_id) REFERENCES warehouses(id) ON DELETE RESTRICT, CONSTRAINT fk_transactions_user FOREIGN KEY (performed_by) REFERENCES users(id) ON DELETE SET NULL );
-- Create Table: suppliers CREATE TABLE suppliers ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name VARCHAR(255) NOT NULL UNIQUE, contact_person VARCHAR(255), email VARCHAR(255), phone VARCHAR(50), address VARCHAR(255), is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL );
-- Create Table: supplier_products CREATE TABLE supplier_products ( supplier_id UUID NOT NULL, product_id UUID NOT NULL, supply_price DECIMAL(12, 2) NOT NULL, PRIMARY KEY (supplier_id, product_id), CONSTRAINT fk_supplier_prod_supplier FOREIGN KEY (supplier_id) REFERENCES suppliers(id) ON DELETE CASCADE, CONSTRAINT fk_supplier_prod_product FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE );
-- Create Table: orders CREATE TABLE orders ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), order_number VARCHAR(100) NOT NULL UNIQUE, supplier_id UUID NOT NULL, warehouse_id UUID NOT NULL, status VARCHAR(50) NOT NULL DEFAULT 'DRAFT', total_amount DECIMAL(12, 2) NOT NULL DEFAULT 0.00, created_by UUID, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, CONSTRAINT fk_orders_supplier FOREIGN KEY (supplier_id) REFERENCES suppliers(id) ON DELETE RESTRICT, CONSTRAINT fk_orders_warehouse FOREIGN KEY (warehouse_id) REFERENCES warehouses(id) ON DELETE RESTRICT, CONSTRAINT fk_orders_user FOREIGN KEY (created_by) REFERENCES users(id) ON DELETE RESTRICT );
-- Create Table: order_items CREATE TABLE order_items ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), order_id UUID NOT NULL, product_id UUID NOT NULL, quantity INTEGER NOT NULL, unit_price DECIMAL(12, 2) NOT NULL, subtotal DECIMAL(12, 2) NOT NULL, CONSTRAINT fk_items_order FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE CASCADE, CONSTRAINT fk_items_product FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE RESTRICT, CONSTRAINT check_positive_quantity CHECK (quantity > 0) );
-- Create Table: shipments CREATE TABLE shipments ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), order_id UUID NOT NULL, tracking_number VARCHAR(100) UNIQUE, carrier VARCHAR(100), status VARCHAR(50) NOT NULL, shipped_at TIMESTAMP WITH TIME ZONE, delivered_at TIMESTAMP WITH TIME ZONE, CONSTRAINT fk_shipments_order FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE RESTRICT );
-- Create Table: audit_logs CREATE TABLE audit_logs ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID, entity_type VARCHAR(100) NOT NULL, entity_id UUID NOT NULL, action VARCHAR(50) NOT NULL, old_value JSONB, new_value JSONB, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, CONSTRAINT fk_audit_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL );
-- Create Table: notifications CREATE TABLE notifications ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL, type VARCHAR(50) NOT NULL, message VARCHAR(255) NOT NULL, is_read BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, CONSTRAINT fk_notifications_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE );
-- Create Table: refresh_tokens CREATE TABLE refresh_tokens ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL, token TEXT NOT NULL UNIQUE, expiry_date TIMESTAMP WITH TIME ZONE NOT NULL, revoked BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, CONSTRAINT fk_refresh_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE );
-- Indexes to optimize performance CREATE INDEX idx_products_sku ON products(sku); CREATE INDEX idx_orders_order_number ON orders(order_number); CREATE INDEX idx_audit_entity ON audit_logs(entity_type, entity_id);
